const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "mysql",
  "inlineSchema": "// LSPD MDT — schéma de base de données\n// SGBD : MySQL (XAMPP en local)\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\n// Prisma 7 : l'URL de connexion ne vit plus ici mais dans prisma.config.ts\n// (pour les migrations) et dans l'adapter passé à PrismaClient (pour le runtime).\ndatasource db {\n  provider = \"mysql\"\n}\n\n// ---------------------------------------------------------------------------\n// HIÉRARCHIE & STRUCTURE\n// ---------------------------------------------------------------------------\n\n/// Grade LSPD. `level` sert à toutes les comparaisons de permissions.\nmodel Rank {\n  id       Int    @id @default(autoincrement())\n  code     String @unique // CHIEF_OF_POLICE, SERGEANT_II, ...\n  name     String // \"Sergeant II\"\n  level    Int    @unique // 100 = Chief of Police, 5 = Cadet\n  category String // COMMAND | CADRES | SUPERVISION | INVESTIGATION | FIELD | ACADEMY\n  order    Int\n\n  users User[]\n\n  @@index([level])\n}\n\nmodel Division {\n  id           Int     @id @default(autoincrement())\n  code         String  @unique // METRO, ASD, TD, IAD, PCG, DB, PATROL\n  name         String\n  shortName    String\n  /// Une division cloisonnée n'expose ses dossiers qu'à ses membres (+ Command Staff).\n  isRestricted Boolean @default(false)\n  /// Grade minimum (level) pour être affecté à cette division. Réglable par le\n  /// Command Staff : 37 = Officer I (Patrol), 38 = Officer II (spécialités).\n  minRankLevel Int     @default(38)\n  order        Int\n\n  subDivisions  SubDivision[]\n  divisionRoles DivisionRole[]\n  members       UserDivision[]\n  documents     DivisionDocument[]\n}\n\nmodel SubDivision {\n  id         Int    @id @default(autoincrement())\n  divisionId Int\n  code       String @unique // METRO_B, METRO_C, METRO_D, METRO_K9, TD_IST, TD_RTS\n  name       String\n  order      Int\n\n  division  Division           @relation(fields: [divisionId], references: [id], onDelete: Cascade)\n  members   UserSubDivision[]\n  roles     DivisionRole[]\n  documents DivisionDocument[]\n\n  @@index([divisionId])\n}\n\n/// Rôle interne à une division (Chief of X, Instructor of X, Member of X...).\n/// Stocké en base et non en dur : la liste peut évoluer sans refonte du code.\nmodel DivisionRole {\n  id            Int  @id @default(autoincrement())\n  divisionId    Int\n  /// Si renseigné, le rôle ne porte que sur cette sous-unité (ex: chef du Platoon D).\n  subDivisionId Int?\n\n  code String @unique // METRO_CHIEF, METRO_PLATOON_INSTRUCTOR, TD_ACADEMY_INSTRUCTOR...\n  name String\n\n  /// Chef de division : droits de superviseur sur tout le périmètre de la division.\n  isDivisionChief Boolean @default(false)\n  /// Responsable d'une sous-unité : droits de superviseur limités à sa sous-unité.\n  isUnitLead      Boolean @default(false)\n  /// Peut encadrer et évaluer des recrues (académie / FTO).\n  canTrain        Boolean @default(false)\n\n  order Int\n\n  division    Division           @relation(fields: [divisionId], references: [id], onDelete: Cascade)\n  subDivision SubDivision?       @relation(fields: [subDivisionId], references: [id], onDelete: SetNull)\n  holders     UserDivisionRole[]\n\n  @@index([divisionId])\n}\n\n/// Document diffusé au sein d'une division par un chef ou un instructeur.\n/// `subDivisionId` nul = destiné à toute la division ; sinon = à ce peloton.\nmodel DivisionDocument {\n  id            Int      @id @default(autoincrement())\n  divisionId    Int\n  subDivisionId Int?\n  title         String\n  content       String   @db.Text\n  fileUrl       String?\n  authorId      Int\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  division    Division     @relation(fields: [divisionId], references: [id], onDelete: Cascade)\n  subDivision SubDivision? @relation(fields: [subDivisionId], references: [id], onDelete: SetNull)\n  author      User         @relation(\"DivDocAuthor\", fields: [authorId], references: [id])\n\n  @@index([divisionId])\n}\n\n/// Note privée de supervision sur un agent, cloisonnée par périmètre de division.\n/// Visible uniquement des superviseurs de ce périmètre et du Command Staff.\nmodel AgentNote {\n  id           Int      @id @default(autoincrement())\n  subjectId    Int\n  authorId     Int\n  divisionCode String\n  body         String   @db.Text\n  createdAt    DateTime @default(now())\n\n  subject User @relation(\"AgentNoteSubject\", fields: [subjectId], references: [id], onDelete: Cascade)\n  author  User @relation(\"AgentNoteAuthor\", fields: [authorId], references: [id])\n\n  @@index([subjectId])\n  @@index([divisionCode])\n}\n\n/// Qualification transverse, indépendante de la division.\n/// Couvre les certifications PPA (CCW 1/2/3), Lincoln Patrol et l'habilitation IFSC.\nmodel Certification {\n  id          Int    @id @default(autoincrement())\n  code        String @unique // CCW1_GLOCK, CCW2_MP5, LINCOLN_PATROL, IFSC...\n  name        String\n  /// PPA | PATROL | INSTRUCTOR\n  category    String\n  /// Niveau CCW (1, 2, 3) ; null hors PPA.\n  level       Int?\n  description String @db.Text\n  order       Int    @default(0)\n\n  holders UserCertification[]\n}\n\n/// Décoration décernée par le Command Staff.\nmodel Medal {\n  id          Int     @id @default(autoincrement())\n  code        String  @unique\n  name        String\n  description String  @db.Text\n  /// Nom d'icône lucide ou chemin d'image.\n  icon        String?\n  /// Couleur d'accent du badge (hex).\n  color       String  @default(\"#c8a24a\")\n  order       Int     @default(0)\n\n  recipients UserMedal[]\n}\n\n// ---------------------------------------------------------------------------\n// AGENTS & AUTHENTIFICATION\n// ---------------------------------------------------------------------------\n\nenum UserStatus {\n  ACTIVE\n  INACTIVE\n  EXCUSED_ABSENCE // Absence justifiée\n  ADMIN_LEAVE // Congé administratif\n  SUSPENDED\n  DISCHARGED // Licencié\n  RESIGNED // Démissionné\n  DECEASED\n}\n\n/// Statut de service d'un agent, tel qu'annoncé à la radio.\nenum DutyStatus {\n  OFF_DUTY /// Hors service (10-08)\n  AVAILABLE /// Disponible (10-08 pris, en patrouille)\n  BUSY /// Occupé (10-06)\n  ON_SCENE /// Sur intervention (10-23)\n  BREAK /// Pause de service (10-10)\n}\n\n/// Origine de la photo de profil.\nenum AvatarSource {\n  DISCORD // synchronisée depuis Discord\n  MANUAL // définie par un superviseur — prioritaire sur Discord\n}\n\nmodel User {\n  id           Int    @id @default(autoincrement())\n  firstName    String\n  lastName     String\n  /// prenom.nom@lspd.core — identifiant de connexion\n  email        String @unique\n  passwordHash String\n\n  /// Matricule de l'agent : 2 chiffres, choisis par la hiérarchie.\n  matricule   String @db.VarChar(2)\n  /// Numéro de badge affiché : matricule + 3 chiffres tirés au hasard.\n  /// Exemple : matricule 28 → badge 28597.\n  badgeNumber String @unique @db.VarChar(5)\n\n  rankId Int\n\n  status UserStatus @default(ACTIVE)\n  phone  String?\n  notes  String?    @db.Text\n\n  /// Date de recrutement — sert à calculer les années de service affichées sur le profil.\n  recruitedAt DateTime @default(now())\n\n  /// Classement académique du Rookie, renseigné à la création du profil.\n  promotion          String?\n  recruitmentSession String?\n\n  /// Statut de service, piloté depuis le module Dispatch.\n  /// Par défaut disponible : tout agent actif figure au tableau de dispatch.\n  dutyStatus DutyStatus @default(AVAILABLE)\n  /// Heure de la dernière prise ou fin de service.\n  dutySince  DateTime?\n\n  // --- Discord -------------------------------------------------------------\n  /// ID Discord (snowflake). Requis pour la connexion via Discord.\n  discordId        String?      @unique\n  discordUsername  String?\n  /// Avatar synchronisé depuis Discord.\n  discordAvatarUrl String?\n  /// Dernière synchronisation avatar/pseudo depuis Discord (rafraîchissement auto).\n  discordSyncedAt  DateTime?\n  /// Avatar imposé par un superviseur — prend le pas sur celui de Discord.\n  manualAvatarUrl  String?\n  avatarSource     AvatarSource @default(DISCORD)\n\n  /// Compte technique hors hiérarchie RP : tous droits, sert au bootstrap.\n  isSuperAdmin Boolean @default(false)\n\n  lastLoginAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  createdById Int?\n\n  /// Agent ayant recruté celui-ci (colonne « Matricule Recruteur »).\n  recruiterId Int?\n  /// Parrain de l'agent (colonne « Matricule Parrain »).\n  sponsorId   Int?\n\n  rank         Rank   @relation(fields: [rankId], references: [id])\n  createdBy    User?  @relation(\"UserCreatedBy\", fields: [createdById], references: [id], onDelete: SetNull)\n  createdUsers User[] @relation(\"UserCreatedBy\")\n  recruiter    User?  @relation(\"UserRecruiter\", fields: [recruiterId], references: [id], onDelete: SetNull)\n  recruited    User[] @relation(\"UserRecruiter\")\n  sponsor      User?  @relation(\"UserSponsor\", fields: [sponsorId], references: [id], onDelete: SetNull)\n  sponsored    User[] @relation(\"UserSponsor\")\n\n  /// Un agent peut appartenir à plusieurs divisions en parallèle.\n  divisions       UserDivision[]\n  divisionRoles   UserDivisionRole[]\n  subDivisions    UserSubDivision[]\n  certifications  UserCertification[]\n  medals          UserMedal[]\n  unionMembership UnionMembership?\n  sessions        Session[]\n  auditLogs       AuditLog[]\n\n  authoredReports          Report[]              @relation(\"ReportAuthor\")\n  reportValidations        ReportValidation[]\n  templatesCreated         ReportTemplate[]\n  warrantsIssued           Warrant[]\n  bolosIssued              Bolo[]\n  announcements            Announcement[]\n  messagesSent             Message[]             @relation(\"MessageSender\")\n  messagesReceived         Message[]             @relation(\"MessageRecipient\")\n  iaCasesOpened            IaCase[]              @relation(\"IaCaseInvestigator\")\n  iaCasesSubject           IaCase[]              @relation(\"IaCaseSubject\")\n  iaCaseNotes              IaCaseNote[]\n  sanctions                Sanction[]            @relation(\"SanctionSubject\")\n  academyDocuments         AcademyDocument[]\n  evaluationsGiven         TraineeEvaluation[]   @relation(\"EvaluationInstructor\")\n  evaluationsGot           TraineeEvaluation[]   @relation(\"EvaluationTrainee\")\n  examsTaken               AcademyExam[]         @relation(\"ExamCandidate\")\n  examsSupervised          AcademyExam[]         @relation(\"ExamExaminer\")\n  divisionDocuments        DivisionDocument[]    @relation(\"DivDocAuthor\")\n  agentNotesReceived       AgentNote[]           @relation(\"AgentNoteSubject\")\n  agentNotesWritten        AgentNote[]           @relation(\"AgentNoteAuthor\")\n  investigationsLed        Investigation[]       @relation(\"InvestigationLead\")\n  investigationNotes       InvestigationNote[]\n  investigationInfos       InvestigationInfo[]\n  academySlotsCreated      AcademyScheduleSlot[] @relation(\"AcademySlotAuthor\")\n  partnershipsAsRookie     Partnership[]         @relation(\"PartnershipRookie\")\n  partnershipsAsInstructor Partnership[]         @relation(\"PartnershipInstructor\")\n  partnershipsCreated      Partnership[]         @relation(\"PartnershipCreatedBy\")\n  partnershipNotes         PartnershipNote[]\n  factionsCreated          Faction[]             @relation(\"FactionCreatedBy\")\n  factionNotes             FactionNote[]\n  dutyShifts               DutyShift[]\n  notifications            Notification[]\n  evidenceFolders          EvidenceFolder[]      @relation(\"EvidenceAuthor\")\n  evidenceItems            EvidenceItem[]        @relation(\"EvidenceItemAuthor\")\n  feedbacks                Feedback[]\n  convocationsReceived     Convocation[]         @relation(\"ConvocationAgent\")\n  convocationsSent         Convocation[]         @relation(\"ConvocationSummoner\")\n  groupMessages            GroupMessage[]\n  channelReads             ChannelRead[]\n  channelsCreated          MessageChannel[]      @relation(\"ChannelCreator\")\n  meetingsCreated          WeeklyMeeting[]\n  gradeChanges             WeeklyGradeChange[]\n  meetingEvents            WeeklyMeetingEvent[]\n  lockersCreated           Locker[]              @relation(\"LockerCreator\")\n  lockerDeposits           LockerItem[]          @relation(\"LockerDepositor\")\n  patrolMembership         PatrolMember?\n  patrolsCreated           Patrol[]              @relation(\"PatrolCreatedBy\")\n  defconChanges            DepartmentStatus[]    @relation(\"DefconSetBy\")\n  civilianRecord           Civilian?             @relation(\"AgentCivilian\")\n  casiersAuthored          Civilian[]            @relation(\"CasierAuthor\")\n  casiersValidated         Civilian[]            @relation(\"CasierValidatedBy\")\n  criminalRecordsAuthored  CriminalRecord[]      @relation(\"CriminalRecordAuthor\")\n  transferRequests         TransferRequest[]     @relation(\"TransferApplicant\")\n  transferDecisions        TransferRequest[]     @relation(\"TransferDecider\")\n  certificatesIssued       FirearmCertificate[]\n  certificationsAwarded    UserCertification[]   @relation(\"CertificationAwardedBy\")\n  medalsAwarded            UserMedal[]           @relation(\"MedalAwardedBy\")\n  avatarsSet               User[]                @relation(\"AvatarSetBy\")\n  avatarSetBy              User?                 @relation(\"AvatarSetBy\", fields: [avatarSetById], references: [id], onDelete: SetNull)\n  avatarSetById            Int?\n\n  @@index([rankId])\n  @@index([status])\n  @@index([discordId])\n}\n\n/// Affectation d'un agent à une division. Plusieurs affectations simultanées\n/// sont possibles ; `isPrimary` désigne celle affichée en premier sur le profil.\nmodel UserDivision {\n  userId     Int\n  divisionId Int\n  isPrimary  Boolean  @default(false)\n  assignedAt DateTime @default(now())\n\n  user     User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  division Division @relation(fields: [divisionId], references: [id], onDelete: Cascade)\n\n  @@id([userId, divisionId])\n  @@index([divisionId])\n}\n\nmodel UserMedal {\n  id          Int       @id @default(autoincrement())\n  userId      Int\n  medalId     Int\n  awardedById Int?\n  /// Motif de la décoration, affiché publiquement sur le profil.\n  /// Null quand la décoration précède la mise en service du MDT.\n  citation    String?   @db.Text\n  /// Date de remise. Null si elle n'est pas connue — on n'affiche alors rien.\n  awardedAt   DateTime?\n\n  user      User  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  medal     Medal @relation(fields: [medalId], references: [id], onDelete: Cascade)\n  awardedBy User? @relation(\"MedalAwardedBy\", fields: [awardedById], references: [id], onDelete: SetNull)\n\n  @@index([userId])\n}\n\nenum UnionRole {\n  REPRESENTATIVE // Représentant Syndical\n  MEMBER // Adhérent\n}\n\n/// Appartenance syndicale — transverse, indépendante de la division.\nmodel UnionMembership {\n  userId   Int       @id\n  role     UnionRole @default(MEMBER)\n  joinedAt DateTime  @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel UserDivisionRole {\n  userId         Int\n  divisionRoleId Int\n  assignedAt     DateTime @default(now())\n\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  divisionRole DivisionRole @relation(fields: [divisionRoleId], references: [id], onDelete: Cascade)\n\n  @@id([userId, divisionRoleId])\n}\n\n/// Un agent Metro peut appartenir à plusieurs pelotons.\nmodel UserSubDivision {\n  userId        Int\n  subDivisionId Int\n  assignedAt    DateTime @default(now())\n\n  user        User        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  subDivision SubDivision @relation(fields: [subDivisionId], references: [id], onDelete: Cascade)\n\n  @@id([userId, subDivisionId])\n}\n\nmodel UserCertification {\n  userId          Int\n  certificationId Int\n  awardedById     Int?\n  obtainedAt      DateTime  @default(now())\n  revokedAt       DateTime?\n  notes           String?   @db.Text\n\n  user          User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  certification Certification @relation(fields: [certificationId], references: [id], onDelete: Cascade)\n  awardedBy     User?         @relation(\"CertificationAwardedBy\", fields: [awardedById], references: [id], onDelete: SetNull)\n\n  @@id([userId, certificationId])\n}\n\nmodel Session {\n  id        String   @id\n  userId    Int\n  expiresAt DateTime\n  ip        String?\n  userAgent String?  @db.Text\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([expiresAt])\n}\n\n/// Journal des actions sensibles — indispensable au RP Internal Affairs.\nmodel AuditLog {\n  id         Int      @id @default(autoincrement())\n  userId     Int?\n  action     String // USER_CREATE, USER_SUSPEND, REPORT_DELETE, IA_CASE_VIEW...\n  targetType String?\n  targetId   String?\n  detail     String?  @db.Text\n  ip         String?\n  createdAt  DateTime @default(now())\n\n  user User? @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  @@index([userId])\n  @@index([action])\n  @@index([createdAt])\n}\n\n// ---------------------------------------------------------------------------\n// RAPPORTS & TEMPLATES\n// ---------------------------------------------------------------------------\n\nenum ReportStatus {\n  DRAFT\n  SUBMITTED\n  APPROVED\n  REJECTED\n  CHANGES_REQUESTED\n}\n\nmodel ReportTemplate {\n  id                 Int     @id @default(autoincrement())\n  code               String  @unique\n  name               String\n  description        String? @db.Text\n  /// Division propriétaire ; null = template départemental.\n  divisionId         Int?\n  /// Catégorie : REPORT (rapports) ou COMPLAINT (plaintes & dépositions).\n  category           String  @default(\"REPORT\")\n  /// Préfixe des références des documents produits (ex: REPORT-ARREST, PLAINTE).\n  referencePrefix    String  @default(\"LSPD\")\n  /// Niveau de grade minimum pour utiliser ce template.\n  minRankLevel       Int     @default(37)\n  requiresValidation Boolean @default(true)\n  isActive           Boolean @default(true)\n  icon               String?\n  order              Int     @default(0)\n\n  createdById Int?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  createdBy User?                   @relation(fields: [createdById], references: [id], onDelete: SetNull)\n  versions  ReportTemplateVersion[]\n  reports   Report[]\n}\n\n/// Versionnage : modifier un template ne casse jamais les rapports déjà soumis.\nmodel ReportTemplateVersion {\n  id         Int      @id @default(autoincrement())\n  templateId Int\n  version    Int\n  /// Définition JSON des champs (type, label, obligatoire, options...).\n  schema     Json\n  createdAt  DateTime @default(now())\n\n  template ReportTemplate @relation(fields: [templateId], references: [id], onDelete: Cascade)\n  reports  Report[]\n\n  @@unique([templateId, version])\n}\n\nmodel Report {\n  id                Int          @id @default(autoincrement())\n  reference         String       @unique // LSPD-2026-000123\n  templateId        Int\n  templateVersionId Int\n  authorId          Int\n  title             String\n  /// Valeurs saisies, conformes au schéma de la version du template.\n  data              Json\n  status            ReportStatus @default(DRAFT)\n\n  /// Signature officielle de l'auteur, apposée au moment de la soumission.\n  authorSignature String?\n\n  incidentAt DateTime?\n  location   String?\n\n  submittedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  template            ReportTemplate         @relation(fields: [templateId], references: [id])\n  templateVersion     ReportTemplateVersion  @relation(fields: [templateVersionId], references: [id])\n  author              User                   @relation(\"ReportAuthor\", fields: [authorId], references: [id])\n  validations         ReportValidation[]\n  civilians           ReportCivilian[]\n  vehicles            ReportVehicle[]\n  charges             ReportCharge[]\n  investigations      InvestigationReport[]\n  factions            FactionReport[]\n  casierLinks         CivilianReport[]\n  criminalRecordLinks CriminalRecordReport[]\n\n  @@index([authorId])\n  @@index([status])\n  @@index([templateId])\n}\n\nmodel ReportValidation {\n  id         Int          @id @default(autoincrement())\n  reportId   Int\n  reviewerId Int\n  decision   ReportStatus\n  comment    String?      @db.Text\n  /// Signature officielle du superviseur, apposée au moment de la décision.\n  signature  String?\n  createdAt  DateTime     @default(now())\n\n  report   Report @relation(fields: [reportId], references: [id], onDelete: Cascade)\n  reviewer User   @relation(fields: [reviewerId], references: [id])\n\n  @@index([reportId])\n}\n\nmodel ReportCivilian {\n  reportId   Int\n  civilianId Int\n  role       String // SUSPECT, VICTIM, WITNESS\n\n  report   Report   @relation(fields: [reportId], references: [id], onDelete: Cascade)\n  civilian Civilian @relation(fields: [civilianId], references: [id], onDelete: Cascade)\n\n  @@id([reportId, civilianId, role])\n}\n\nmodel ReportVehicle {\n  reportId  Int\n  vehicleId Int\n\n  report  Report  @relation(fields: [reportId], references: [id], onDelete: Cascade)\n  vehicle Vehicle @relation(fields: [vehicleId], references: [id], onDelete: Cascade)\n\n  @@id([reportId, vehicleId])\n}\n\nmodel ReportCharge {\n  id          Int     @id @default(autoincrement())\n  reportId    Int\n  penalCodeId Int\n  count       Int     @default(1)\n  notes       String? @db.Text\n\n  report    Report    @relation(fields: [reportId], references: [id], onDelete: Cascade)\n  penalCode PenalCode @relation(fields: [penalCodeId], references: [id])\n\n  @@index([reportId])\n}\n\n// ---------------------------------------------------------------------------\n// BASE CIVILS\n// ---------------------------------------------------------------------------\n\n/// Fiche d'un individu = son casier judiciaire (identité + antécédents).\nmodel Civilian {\n  id                 Int       @id @default(autoincrement())\n  /// Référence unique du casier : CASIER-2026-0001.\n  reference          String    @unique\n  firstName          String\n  lastName           String\n  dateOfBirth        DateTime?\n  placeOfBirth       String?\n  nationality        String?\n  /// Genre : \"Homme\" ou \"Femme\".\n  gender             String?\n  address            String?\n  phone              String?\n  height             String?\n  weight             String?\n  eyeColor           String?\n  hairColor          String?\n  /// Tatouages apparents ? + description éventuelle.\n  hasTattoos         Boolean   @default(false)\n  tattoosDescription String?\n  /// Revendication d'un groupuscule (texte libre).\n  groupuscule        String?\n  photoUrl           String?\n  notes              String?   @db.Text\n  /// Signalé comme dangereux — affiche un avertissement dans le MDT.\n  isFlagged          Boolean   @default(false)\n  flagReason         String?\n\n  /// Agent rédacteur du casier + sa signature (le casier est un document signé).\n  authorId            Int\n  authorSignature     String?\n  /// Validation par un superviseur (Sgt I+).\n  validatedById       Int?\n  validatedAt         DateTime?\n  validationSignature String?\n\n  /// Agent du LSPD correspondant à ce civil, s'il y en a un. Tout agent est\n  /// automatiquement fiché comme civil ; ce lien évite les doublons.\n  agentId Int? @unique\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  agent       User? @relation(\"AgentCivilian\", fields: [agentId], references: [id], onDelete: SetNull)\n  author      User  @relation(\"CasierAuthor\", fields: [authorId], references: [id])\n  validatedBy User? @relation(\"CasierValidatedBy\", fields: [validatedById], references: [id], onDelete: SetNull)\n\n  vehicles        Vehicle[]\n  licenses        License[]\n  criminalRecords CriminalRecord[]\n  warrants        Warrant[]\n  bolos           Bolo[]\n  reports         ReportCivilian[]\n  linkedReports   CivilianReport[]\n  firearmCerts    FirearmCertificate[]\n  factions        FactionCivilian[]\n\n  @@index([lastName, firstName])\n  @@index([authorId])\n}\n\nmodel Vehicle {\n  id          Int     @id @default(autoincrement())\n  plate       String  @unique\n  make        String?\n  model       String?\n  color       String?\n  year        Int?\n  ownerId     Int?\n  isStolen    Boolean @default(false)\n  isImpounded Boolean @default(false)\n  notes       String? @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  owner   Civilian?       @relation(fields: [ownerId], references: [id], onDelete: SetNull)\n  reports ReportVehicle[]\n  bolos   Bolo[]\n\n  @@index([ownerId])\n}\n\nmodel License {\n  id         Int       @id @default(autoincrement())\n  civilianId Int\n  type       String // DRIVER, FIREARM, HUNTING, PILOT, COMMERCIAL\n  status     String    @default(\"VALID\") // VALID, SUSPENDED, REVOKED, EXPIRED\n  issuedAt   DateTime  @default(now())\n  expiresAt  DateTime?\n  notes      String?   @db.Text\n\n  civilian Civilian @relation(fields: [civilianId], references: [id], onDelete: Cascade)\n\n  @@index([civilianId])\n}\n\n/// Une infraction du casier judiciaire d'un individu.\nmodel CriminalRecord {\n  id           Int      @id @default(autoincrement())\n  /// Sous-référence citable : CASIER-2026-0001-01.\n  reference    String?\n  civilianId   Int\n  /// Agent ayant inscrit l'infraction au casier.\n  authorId     Int\n  description  String   @db.Text\n  sentence     String?\n  fine         Int?\n  /// Observations supplémentaires libres.\n  observations String?  @db.Text\n  occurredAt   DateTime @default(now())\n  createdAt    DateTime @default(now())\n\n  civilian      Civilian               @relation(fields: [civilianId], references: [id], onDelete: Cascade)\n  author        User                   @relation(\"CriminalRecordAuthor\", fields: [authorId], references: [id])\n  /// Un même fait peut réunir plusieurs motifs (infractions). Vide = hors nomenclature.\n  charges       CriminalRecordCharge[]\n  /// Rapports rattachés à cette infraction (arrestation, interrogatoire…).\n  linkedReports CriminalRecordReport[]\n  /// Renvois vers d'autres infractions du casier (anciennes arrestations).\n  references    CriminalRecordLink[]   @relation(\"RecordRefFrom\")\n  referencedBy  CriminalRecordLink[]   @relation(\"RecordRefTo\")\n\n  @@index([civilianId])\n  @@index([authorId])\n}\n\n/// Motif d'une entrée de casier : lien vers un article du code pénal.\nmodel CriminalRecordCharge {\n  id               Int @id @default(autoincrement())\n  criminalRecordId Int\n  penalCodeId      Int\n\n  record    CriminalRecord @relation(fields: [criminalRecordId], references: [id], onDelete: Cascade)\n  penalCode PenalCode      @relation(fields: [penalCodeId], references: [id], onDelete: Cascade)\n\n  @@unique([criminalRecordId, penalCodeId])\n  @@index([penalCodeId])\n}\n\n/// Rapport rattaché à un casier (niveau fiche).\nmodel CivilianReport {\n  civilianId Int\n  reportId   Int\n  linkedAt   DateTime @default(now())\n\n  civilian Civilian @relation(fields: [civilianId], references: [id], onDelete: Cascade)\n  report   Report   @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@id([civilianId, reportId])\n  @@index([reportId])\n}\n\n/// Rapport rattaché à une infraction précise du casier.\nmodel CriminalRecordReport {\n  criminalRecordId Int\n  reportId         Int\n  linkedAt         DateTime @default(now())\n\n  record CriminalRecord @relation(fields: [criminalRecordId], references: [id], onDelete: Cascade)\n  report Report         @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@id([criminalRecordId, reportId])\n  @@index([reportId])\n}\n\n/// Renvoi entre deux infractions d'un même casier (auto-relation).\nmodel CriminalRecordLink {\n  fromId Int\n  toId   Int\n\n  from CriminalRecord @relation(\"RecordRefFrom\", fields: [fromId], references: [id], onDelete: Cascade)\n  to   CriminalRecord @relation(\"RecordRefTo\", fields: [toId], references: [id], onDelete: Cascade)\n\n  @@id([fromId, toId])\n  @@index([toId])\n}\n\n/// Firearm Security Certificate, délivré par les agents certifiés IFSC.\nmodel FirearmCertificate {\n  id           Int       @id @default(autoincrement())\n  /// Identité du titulaire saisie librement (la base civile n'est plus requise).\n  subjectName  String    @default(\"\")\n  civilianId   Int?\n  issuedById   Int\n  reference    String    @unique\n  status       String    @default(\"VALID\") // VALID, REVOKED, EXPIRED\n  issuedAt     DateTime  @default(now())\n  expiresAt    DateTime?\n  revokedAt    DateTime?\n  revokeReason String?   @db.Text\n\n  civilian Civilian? @relation(fields: [civilianId], references: [id], onDelete: SetNull)\n  issuedBy User      @relation(fields: [issuedById], references: [id])\n\n  @@index([civilianId])\n}\n\n// ---------------------------------------------------------------------------\n// MANDATS & BOLO\n// ---------------------------------------------------------------------------\n\nmodel Warrant {\n  id          Int       @id @default(autoincrement())\n  reference   String    @unique\n  /// Identité de l'individu visé, saisie librement.\n  subjectName String    @default(\"\")\n  civilianId  Int?\n  issuedById  Int\n  type        String // ARREST, SEARCH\n  reason      String    @db.Text\n  /// Signature officielle de l'agent émetteur.\n  signature   String?\n  status      String    @default(\"ACTIVE\") // ACTIVE, EXECUTED, CANCELLED, EXPIRED\n  expiresAt   DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  civilian Civilian? @relation(fields: [civilianId], references: [id], onDelete: SetNull)\n  issuedBy User      @relation(fields: [issuedById], references: [id])\n\n  @@index([status])\n}\n\nmodel Bolo {\n  id          Int      @id @default(autoincrement())\n  reference   String   @unique\n  title       String\n  type        String // PERSON, VEHICLE, OTHER\n  /// Identité de la personne concernée, saisie librement (type PERSON).\n  subjectName String   @default(\"\")\n  description String   @db.Text\n  /// Signature officielle de l'agent émetteur.\n  signature   String?\n  priority    String   @default(\"MEDIUM\") // LOW, MEDIUM, HIGH, CRITICAL\n  status      String   @default(\"ACTIVE\")\n  civilianId  Int?\n  vehicleId   Int?\n  issuedById  Int\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  civilian Civilian? @relation(fields: [civilianId], references: [id], onDelete: SetNull)\n  vehicle  Vehicle?  @relation(fields: [vehicleId], references: [id], onDelete: SetNull)\n  issuedBy User      @relation(fields: [issuedById], references: [id])\n\n  @@index([status])\n}\n\n// ---------------------------------------------------------------------------\n// CODES RADIO & CODE PÉNAL\n// ---------------------------------------------------------------------------\n\n/// Référentiel opérationnel : ten-codes, codes de patrouille, call signs,\n/// alphabet OTAN, catégories d'armement et niveaux DEFCON.\nmodel RadioCode {\n  id          Int     @id @default(autoincrement())\n  /// TEN_CODE | PATROL_CODE | CALL_SIGN | PHONETIC | WEAPON_CATEGORY | DEFCON\n  category    String\n  code        String\n  label       String\n  description String? @db.Text\n  order       Int     @default(0)\n\n  @@unique([category, code])\n}\n\n// ---------------------------------------------------------------------------\n// ÉTAT DU DÉPARTEMENT\n// ---------------------------------------------------------------------------\n\n/// État opérationnel du département — enregistrement unique (id = 1).\nmodel DepartmentStatus {\n  id           Int     @id @default(1)\n  /// Niveau DEFCON en vigueur : 5 (préparation normale) à 1 (état de guerre).\n  defconLevel  Int     @default(5)\n  /// Motif du niveau, affiché à tous les agents.\n  defconReason String? @db.Text\n\n  updatedById Int?\n  updatedAt   DateTime @updatedAt\n\n  updatedBy User? @relation(\"DefconSetBy\", fields: [updatedById], references: [id], onDelete: SetNull)\n}\n\n// ---------------------------------------------------------------------------\n// DISPATCH & UNITÉS\n// ---------------------------------------------------------------------------\n\n/// Patrouille constituée sur le terrain : un call sign, un numéro et ses agents.\n/// Exemple : ADAM-12, patrouille à deux effectifs.\nmodel Patrol {\n  id       Int     @id @default(autoincrement())\n  /// Call sign réglementaire : LINCOLN, ADAM, TANGO, X-Ray, DAVID, K9…\n  callSign String\n  /// Numéro d'unité, libre. ADAM-12, LINCOLN-3…\n  number   String?\n  /// AVAILABLE | BUSY | ON_SCENE | RETURNING\n  status   String  @default(\"AVAILABLE\")\n  /// Zone ou secteur de patrouille.\n  sector   String?\n  notes    String? @db.Text\n  /// Ordre d'affichage sur le tableau de dispatch (glisser-déposer).\n  order    Int     @default(0)\n\n  createdById Int?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  createdBy User?          @relation(\"PatrolCreatedBy\", fields: [createdById], references: [id], onDelete: SetNull)\n  members   PatrolMember[]\n\n  @@index([status])\n}\n\n/// Affectation d'un agent à une patrouille.\n/// `userId` est unique : un agent ne peut servir que dans une patrouille à la fois.\nmodel PatrolMember {\n  patrolId Int\n  userId   Int      @unique\n  /// Chef de bord de la patrouille.\n  isLead   Boolean  @default(false)\n  joinedAt DateTime @default(now())\n\n  patrol Patrol @relation(fields: [patrolId], references: [id], onDelete: Cascade)\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@id([patrolId, userId])\n}\n\n/// Vacation de service : temps de présence d'un agent « en service » sur le MDT.\n/// `lastPingAt` est rafraîchi tant que la page reste ouverte ; si l'agent ferme\n/// sa page sans terminer, le temps s'arrête au dernier ping.\nmodel DutyShift {\n  id         Int       @id @default(autoincrement())\n  userId     Int\n  startedAt  DateTime  @default(now())\n  lastPingAt DateTime  @default(now())\n  endedAt    DateTime?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([startedAt])\n}\n\n/// Notification destinée à un agent (rapport validé, message reçu, candidature…).\nmodel Notification {\n  id        Int       @id @default(autoincrement())\n  userId    Int\n  type      String\n  title     String\n  body      String?   @db.Text\n  link      String?\n  readAt    DateTime?\n  createdAt DateTime  @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, readAt])\n}\n\n/// Dossier de preuves regroupant plusieurs pièces (images ou liens).\n/// Un détective peut le rattacher à une enquête.\nmodel EvidenceFolder {\n  id              Int      @id @default(autoincrement())\n  reference       String   @unique // PREUVE-2026-0001\n  title           String\n  description     String?  @db.Text\n  authorId        Int\n  investigationId Int?\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  author        User           @relation(\"EvidenceAuthor\", fields: [authorId], references: [id])\n  investigation Investigation? @relation(fields: [investigationId], references: [id], onDelete: SetNull)\n  items         EvidenceItem[]\n\n  @@index([authorId])\n  @@index([investigationId])\n}\n\n/// Retour ou suggestion d'un agent sur l'amélioration du MDT.\nmodel Feedback {\n  id        Int      @id @default(autoincrement())\n  userId    Int\n  type      String   @default(\"SUGGESTION\") // SUGGESTION, BUG, OTHER\n  message   String   @db.Text\n  status    String   @default(\"NEW\") // NEW, REVIEWED\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n}\n\n/// Canal de discussion personnalisé créé par le Command Staff.\n/// Les 5 canaux prédéfinis restent en code ; ceux-ci s'y ajoutent.\nmodel MessageChannel {\n  id            Int      @id @default(autoincrement())\n  key           String   @unique\n  name          String\n  /// Codes de grade autorisés (ex: [\"SERGEANT_I\",\"LIEUTENANT_I\"]).\n  rankCodes     Json\n  /// Identifiants d'agents autorisés en plus des grades.\n  userIds       Json\n  /// Codes de division dont les membres ont accès (ex: [\"METRO\",\"IAD\"]).\n  divisionCodes Json?\n  /// Codes d'habilitation/certification donnant accès (ex: [\"ISTC\",\"IFSC\"]).\n  certCodes     Json?\n  createdById   Int?\n  createdAt     DateTime @default(now())\n\n  createdBy User? @relation(\"ChannelCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n}\n\n/// Message d'un canal de discussion par catégorie de grade.\nmodel GroupMessage {\n  id        Int      @id @default(autoincrement())\n  channel   String\n  senderId  Int\n  body      String?  @db.Text\n  imageUrl  String?  @db.Text\n  createdAt DateTime @default(now())\n\n  sender User @relation(fields: [senderId], references: [id], onDelete: Cascade)\n\n  @@index([channel, createdAt])\n}\n\n/// Dernière lecture d'un canal par un agent : sert à compter les messages non\n/// lus (bulle rouge à côté du canal). Une ligne par (agent, canal).\nmodel ChannelRead {\n  id         Int      @id @default(autoincrement())\n  userId     Int\n  channel    String\n  lastReadAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, channel])\n}\n\n/// Casier physique du poste : les agents y annoncent le dépôt d'objets.\nmodel Locker {\n  id          Int      @id @default(autoincrement())\n  name        String\n  /// Code d'accès physique du casier (facultatif).\n  accessCode  String?\n  /// Casier fourni par défaut : non supprimable.\n  isDefault   Boolean  @default(false)\n  order       Int      @default(0)\n  createdById Int?\n  createdAt   DateTime @default(now())\n\n  createdBy User?        @relation(\"LockerCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n  items     LockerItem[]\n}\n\n/// Objet déposé dans un casier, annoncé par un agent.\nmodel LockerItem {\n  id            Int      @id @default(autoincrement())\n  lockerId      Int\n  label         String\n  quantity      Int?\n  depositedById Int\n  createdAt     DateTime @default(now())\n\n  locker      Locker @relation(fields: [lockerId], references: [id], onDelete: Cascade)\n  depositedBy User   @relation(\"LockerDepositor\", fields: [depositedById], references: [id])\n\n  @@index([lockerId])\n}\n\n/// Récapitulatif d'une réunion hebdomadaire / cérémonie de fin de semaine.\nmodel WeeklyMeeting {\n  id          Int       @id @default(autoincrement())\n  summary     String    @db.Text\n  /// Date de la réunion de fin de semaine (choisie par le rédacteur).\n  meetingDate DateTime?\n  /// Signature officielle du rédacteur.\n  signature   String?\n  createdById Int\n  createdAt   DateTime  @default(now())\n\n  createdBy    User                 @relation(fields: [createdById], references: [id])\n  gradeChanges WeeklyGradeChange[]\n  events       WeeklyMeetingEvent[]\n}\n\n/// Autre annonce de réunion : avertissement, départ du service ou décès\n/// (affichage seul).\nmodel WeeklyMeetingEvent {\n  id        Int     @id @default(autoincrement())\n  meetingId Int\n  userId    Int\n  agentName String\n  rankName  String\n  type      String // WARNING | DEPARTURE | DEATH\n  reason    String? @db.Text\n\n  meeting WeeklyMeeting @relation(fields: [meetingId], references: [id], onDelete: Cascade)\n  agent   User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([meetingId])\n}\n\n/// Montée / descente de grade annoncée lors d'une réunion (affichage seul,\n/// n'affecte pas le grade réel de l'agent).\nmodel WeeklyGradeChange {\n  id           Int    @id @default(autoincrement())\n  meetingId    Int\n  userId       Int\n  /// Instantanés pour un affichage stable, même si le grade change ensuite.\n  agentName    String\n  fromRankName String\n  toRankName   String\n  direction    String // PROMOTION | DEMOTION\n\n  meeting WeeklyMeeting @relation(fields: [meetingId], references: [id], onDelete: Cascade)\n  agent   User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\n/// Convocation d'un agent dans un bureau ou un lieu précis par un superviseur.\nmodel Convocation {\n  id             Int       @id @default(autoincrement())\n  agentId        Int\n  summonedById   Int\n  location       String\n  reason         String    @db.Text\n  scheduledAt    DateTime?\n  status         String    @default(\"PENDING\") // PENDING, ACKNOWLEDGED, CANCELLED\n  acknowledgedAt DateTime?\n  createdAt      DateTime  @default(now())\n\n  agent      User @relation(\"ConvocationAgent\", fields: [agentId], references: [id], onDelete: Cascade)\n  summonedBy User @relation(\"ConvocationSummoner\", fields: [summonedById], references: [id])\n\n  @@index([agentId, status])\n}\n\n/// Pièce d'un dossier de preuves : image téléversée (fichier serveur) ou lien.\nmodel EvidenceItem {\n  id        Int      @id @default(autoincrement())\n  folderId  Int\n  kind      String   @default(\"IMAGE\") // IMAGE = fichier téléversé, LINK = lien externe\n  url       String   @db.Text\n  caption   String?\n  addedById Int\n  createdAt DateTime @default(now())\n\n  folder  EvidenceFolder @relation(fields: [folderId], references: [id], onDelete: Cascade)\n  addedBy User           @relation(\"EvidenceItemAuthor\", fields: [addedById], references: [id])\n\n  @@index([folderId])\n}\n\n/// Texte de référence du département : droits Miranda, fiches circulaires,\n/// procédures. Éditable par les superviseurs.\nmodel ReferenceText {\n  id       Int     @id @default(autoincrement())\n  code     String  @unique\n  title    String\n  /// MIRANDA | PROCEDURE | CIRCULAIRE\n  category String\n  content  String  @db.Text\n  notes    String? @db.Text\n  order    Int     @default(0)\n\n  updatedAt DateTime @updatedAt\n}\n\n/// Code pénal de l'État de San Andreas.\nmodel PenalCode {\n  id              Int     @id @default(autoincrement())\n  /// Article : 1.A, 2.O, 5.AE…\n  code            String  @unique\n  title           String\n  /// CONTRAVENTION | DELIT MINEUR | DELIT MAJEUR | CRIME | CRIME FEDERAL | CRIME FINANCIER\n  category        String\n  /// Complément de peine : confiscation, retrait de permis, mise en fourrière…\n  description     String? @db.Text\n  /// Amende maximale, en dollars.\n  fine            Int?\n  /// Peine de détention en minutes. Null si aucune peine privative de liberté.\n  jailTime        Int?\n  /// Peine de perpétuité : elle ne se compare pas aux peines chiffrées.\n  isLifeSentence  Boolean @default(false)\n  /// L'affaire relève du Department of Justice (colonne « DOJ ? »).\n  requiresDoj     Boolean @default(false)\n  /// Article renvoyé au juge uniquement en cas de cumul avec un délit supérieur.\n  dojOnCumulation Boolean @default(false)\n  /// Ordre d'affichage, tel que dans le document officiel.\n  order           Int     @default(0)\n  points          Int?\n\n  charges         ReportCharge[]\n  criminalRecords CriminalRecordCharge[]\n\n  @@index([category])\n}\n\n// ---------------------------------------------------------------------------\n// ANNONCES & MESSAGERIE\n// ---------------------------------------------------------------------------\n\nmodel Announcement {\n  id               Int      @id @default(autoincrement())\n  title            String\n  body             String   @db.Text\n  priority         String   @default(\"NORMAL\") // NORMAL, IMPORTANT, URGENT\n  /// null = toutes divisions\n  divisionId       Int?\n  /// Visible par les Cadets et Probationary Officers.\n  visibleToAcademy Boolean  @default(false)\n  isPinned         Boolean  @default(false)\n  authorId         Int\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  author User @relation(fields: [authorId], references: [id])\n\n  @@index([divisionId])\n}\n\nmodel Message {\n  id          Int       @id @default(autoincrement())\n  senderId    Int\n  recipientId Int\n  subject     String\n  body        String    @db.Text\n  imageUrl    String?   @db.Text\n  readAt      DateTime?\n  createdAt   DateTime  @default(now())\n\n  sender    User @relation(\"MessageSender\", fields: [senderId], references: [id], onDelete: Cascade)\n  recipient User @relation(\"MessageRecipient\", fields: [recipientId], references: [id], onDelete: Cascade)\n\n  @@index([recipientId, readAt])\n}\n\n// ---------------------------------------------------------------------------\n// INTERNAL AFFAIRS\n// ---------------------------------------------------------------------------\n\nmodel IaCase {\n  id             Int       @id @default(autoincrement())\n  reference      String    @unique\n  subjectId      Int\n  investigatorId Int\n  title          String\n  summary        String    @db.Text\n  severity       String    @default(\"MEDIUM\") // LOW, MEDIUM, HIGH, CRITICAL\n  status         String    @default(\"OPEN\") // OPEN, INVESTIGATING, CLOSED, DISMISSED\n  outcome        String?   @db.Text\n  closedAt       DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  subject      User         @relation(\"IaCaseSubject\", fields: [subjectId], references: [id])\n  investigator User         @relation(\"IaCaseInvestigator\", fields: [investigatorId], references: [id])\n  notes        IaCaseNote[]\n  sanctions    Sanction[]\n\n  @@index([status])\n}\n\nmodel IaCaseNote {\n  id        Int      @id @default(autoincrement())\n  caseId    Int\n  authorId  Int\n  body      String   @db.Text\n  createdAt DateTime @default(now())\n\n  case   IaCase @relation(fields: [caseId], references: [id], onDelete: Cascade)\n  author User   @relation(fields: [authorId], references: [id])\n\n  @@index([caseId])\n}\n\nmodel Sanction {\n  id        Int       @id @default(autoincrement())\n  subjectId Int\n  caseId    Int?\n  type      String // WARNING, REPRIMAND, SUSPENSION, DEMOTION, TERMINATION\n  reason    String    @db.Text\n  /// Une sanction publique apparaît sur le profil consultable par tous.\n  /// Les sanctions non publiques restent visibles par l'IAD et le Command Staff.\n  isPublic  Boolean   @default(false)\n  startsAt  DateTime  @default(now())\n  endsAt    DateTime?\n  createdAt DateTime  @default(now())\n\n  subject User    @relation(\"SanctionSubject\", fields: [subjectId], references: [id], onDelete: Cascade)\n  case    IaCase? @relation(fields: [caseId], references: [id], onDelete: SetNull)\n\n  @@index([subjectId])\n}\n\n// ---------------------------------------------------------------------------\n// BUREAU DES DÉTECTIVES — enquêtes\n// ---------------------------------------------------------------------------\n\n/// Dossier d'enquête du Detective Bureau, rattachable à des rapports existants.\nmodel Investigation {\n  id        Int       @id @default(autoincrement())\n  reference String    @unique // INV-2026-0001\n  leadId    Int\n  title     String\n  summary   String    @db.Text\n  status    String    @default(\"OPEN\") // OPEN, ACTIVE, CLOSED, ARCHIVED\n  outcome   String?   @db.Text\n  closedAt  DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  lead            User                   @relation(\"InvestigationLead\", fields: [leadId], references: [id])\n  notes           InvestigationNote[]\n  infos           InvestigationInfo[]\n  reports         InvestigationReport[]\n  factions        FactionInvestigation[]\n  evidenceFolders EvidenceFolder[]\n\n  @@index([status])\n  @@index([leadId])\n}\n\n/// Élément d'information rattaché à une enquête (suspect, indice, lieu…).\nmodel InvestigationInfo {\n  id              Int      @id @default(autoincrement())\n  investigationId Int\n  label           String\n  content         String   @db.Text\n  authorId        Int\n  createdAt       DateTime @default(now())\n\n  investigation Investigation @relation(fields: [investigationId], references: [id], onDelete: Cascade)\n  author        User          @relation(fields: [authorId], references: [id])\n\n  @@index([investigationId])\n}\n\n/// Groupuscule / faction s'étant revendiqué en ville, suivi par le Detective Bureau.\nmodel Faction {\n  id          Int      @id @default(autoincrement())\n  name        String\n  description String   @db.Text\n  status      String   @default(\"ACTIVE\") // ACTIVE, WATCHED, DISMANTLED\n  createdById Int?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  createdBy      User?                  @relation(\"FactionCreatedBy\", fields: [createdById], references: [id], onDelete: SetNull)\n  notes          FactionNote[]\n  reports        FactionReport[]\n  investigations FactionInvestigation[]\n  civilians      FactionCivilian[]\n\n  @@index([status])\n}\n\nmodel FactionNote {\n  id        Int      @id @default(autoincrement())\n  factionId Int\n  authorId  Int\n  body      String   @db.Text\n  createdAt DateTime @default(now())\n\n  faction Faction @relation(fields: [factionId], references: [id], onDelete: Cascade)\n  author  User    @relation(fields: [authorId], references: [id])\n\n  @@index([factionId])\n}\n\nmodel FactionReport {\n  factionId Int\n  reportId  Int\n  linkedAt  DateTime @default(now())\n\n  faction Faction @relation(fields: [factionId], references: [id], onDelete: Cascade)\n  report  Report  @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@id([factionId, reportId])\n  @@index([reportId])\n}\n\nmodel FactionInvestigation {\n  factionId       Int\n  investigationId Int\n  linkedAt        DateTime @default(now())\n\n  faction       Faction       @relation(fields: [factionId], references: [id], onDelete: Cascade)\n  investigation Investigation @relation(fields: [investigationId], references: [id], onDelete: Cascade)\n\n  @@id([factionId, investigationId])\n  @@index([investigationId])\n}\n\nmodel FactionCivilian {\n  factionId  Int\n  civilianId Int\n  role       String?\n  linkedAt   DateTime @default(now())\n\n  faction  Faction  @relation(fields: [factionId], references: [id], onDelete: Cascade)\n  civilian Civilian @relation(fields: [civilianId], references: [id], onDelete: Cascade)\n\n  @@id([factionId, civilianId])\n  @@index([civilianId])\n}\n\nmodel InvestigationNote {\n  id              Int      @id @default(autoincrement())\n  investigationId Int\n  authorId        Int\n  body            String   @db.Text\n  createdAt       DateTime @default(now())\n\n  investigation Investigation @relation(fields: [investigationId], references: [id], onDelete: Cascade)\n  author        User          @relation(fields: [authorId], references: [id])\n\n  @@index([investigationId])\n}\n\n/// Rattachement d'un rapport existant à une enquête (plusieurs rapports possibles).\nmodel InvestigationReport {\n  investigationId Int\n  reportId        Int\n  linkedAt        DateTime @default(now())\n\n  investigation Investigation @relation(fields: [investigationId], references: [id], onDelete: Cascade)\n  report        Report        @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@id([investigationId, reportId])\n  @@index([reportId])\n}\n\n// ---------------------------------------------------------------------------\n// ACADÉMIE\n// ---------------------------------------------------------------------------\n\n/// Promotion académique — liste gérée par le Chief Office ; le nom est reporté\n/// sur le champ `User.promotion` du Rookie affecté.\nmodel AcademyPromotion {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  createdAt DateTime @default(now())\n}\n\n/// Binôme de formation : une recrue (Police Officer I) attitrée à un instructeur\n/// (Field Training Officer). Géré par les gradés (Sergeant II et au-dessus).\nmodel Partnership {\n  id           Int      @id @default(autoincrement())\n  rookieId     Int\n  instructorId Int\n  createdById  Int?\n  createdAt    DateTime @default(now())\n\n  rookie     User              @relation(\"PartnershipRookie\", fields: [rookieId], references: [id], onDelete: Cascade)\n  instructor User              @relation(\"PartnershipInstructor\", fields: [instructorId], references: [id], onDelete: Cascade)\n  createdBy  User?             @relation(\"PartnershipCreatedBy\", fields: [createdById], references: [id], onDelete: SetNull)\n  notes      PartnershipNote[]\n\n  @@index([rookieId])\n  @@index([instructorId])\n}\n\n/// Note sur un binôme. `visibility` : PUBLIC (tous), BOTH (les deux membres),\n/// ROOKIE (la recrue seule) ou INSTRUCTOR (l'instructeur seul). Les gestionnaires\n/// et le Command Staff voient toujours tout.\nmodel PartnershipNote {\n  id            Int      @id @default(autoincrement())\n  partnershipId Int\n  authorId      Int\n  body          String   @db.Text\n  visibility    String   @default(\"BOTH\")\n  createdAt     DateTime @default(now())\n\n  partnership Partnership @relation(fields: [partnershipId], references: [id], onDelete: Cascade)\n  author      User        @relation(fields: [authorId], references: [id])\n\n  @@index([partnershipId])\n}\n\n/// Créneau récurrent du planning hebdomadaire de l'académie.\n/// `dayOfWeek` : 0 = lundi … 6 = dimanche. `startMin`/`endMin` : minutes depuis\n/// minuit (0-1439). La fenêtre d'affichage court de 12h00 à 06h00 du matin.\nmodel AcademyScheduleSlot {\n  id          Int      @id @default(autoincrement())\n  dayOfWeek   Int\n  startMin    Int\n  endMin      Int\n  title       String\n  location    String?\n  details     String?  @db.Text\n  createdById Int?\n  createdAt   DateTime @default(now())\n\n  createdBy User? @relation(\"AcademySlotAuthor\", fields: [createdById], references: [id], onDelete: SetNull)\n\n  @@index([dayOfWeek])\n}\n\nmodel AcademyCourse {\n  id          Int     @id @default(autoincrement())\n  code        String  @unique\n  title       String\n  description String  @db.Text\n  order       Int     @default(0)\n  isPublished Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  documents   AcademyDocument[]\n  sessions    AcademySession[]\n  evaluations TraineeEvaluation[]\n}\n\nmodel AcademyDocument {\n  id         Int      @id @default(autoincrement())\n  courseId   Int?\n  title      String\n  content    String   @db.Text\n  fileUrl    String?\n  authorId   Int\n  /// ALL = visible des rookies et instructeurs ; INSTRUCTORS = instructeurs seuls.\n  visibility String   @default(\"ALL\")\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  course AcademyCourse? @relation(fields: [courseId], references: [id], onDelete: SetNull)\n  author User           @relation(fields: [authorId], references: [id])\n\n  @@index([courseId])\n}\n\nmodel AcademySession {\n  id        Int       @id @default(autoincrement())\n  courseId  Int?\n  title     String\n  startsAt  DateTime\n  endsAt    DateTime?\n  location  String?\n  maxSeats  Int?\n  notes     String?   @db.Text\n  createdAt DateTime  @default(now())\n\n  course AcademyCourse? @relation(fields: [courseId], references: [id], onDelete: SetNull)\n\n  @@index([startsAt])\n}\n\n/// Épreuve notée de l'examen de sortie d'académie.\nmodel AcademyExamSubject {\n  id        Int    @id @default(autoincrement())\n  code      String @unique\n  name      String\n  maxPoints Int\n  order     Int    @default(0)\n\n  scores AcademyExamScore[]\n}\n\n/// Examen de sortie d'académie d'un candidat.\n/// Admission à partir de 80 % — seuil défini par le règlement du département.\nmodel AcademyExam {\n  id          Int      @id @default(autoincrement())\n  candidateId Int\n  examinerId  Int?\n  examinedAt  DateTime @default(now())\n  /// Total obtenu, toutes épreuves confondues.\n  totalPoints Int      @default(0)\n  /// Total maximum possible au moment de l'examen (les épreuves peuvent évoluer).\n  maxPoints   Int      @default(0)\n  /// Pourcentage de réussite, arrondi à l'entier.\n  percentage  Int      @default(0)\n  passed      Boolean  @default(false)\n  comment     String?  @db.Text\n\n  candidate User?              @relation(\"ExamCandidate\", fields: [candidateId], references: [id], onDelete: Cascade, map: \"AcademyExam_candidate_fkey\")\n  examiner  User?              @relation(\"ExamExaminer\", fields: [examinerId], references: [id], onDelete: SetNull)\n  scores    AcademyExamScore[]\n\n  @@index([candidateId])\n}\n\nmodel AcademyExamScore {\n  id        Int @id @default(autoincrement())\n  examId    Int\n  subjectId Int\n  points    Int @default(0)\n\n  exam    AcademyExam        @relation(fields: [examId], references: [id], onDelete: Cascade)\n  subject AcademyExamSubject @relation(fields: [subjectId], references: [id], onDelete: Cascade)\n\n  @@unique([examId, subjectId])\n}\n\nmodel TraineeEvaluation {\n  id           Int      @id @default(autoincrement())\n  traineeId    Int\n  instructorId Int\n  courseId     Int?\n  score        Int? // 0-100\n  passed       Boolean  @default(false)\n  comment      String   @db.Text\n  createdAt    DateTime @default(now())\n\n  trainee    User           @relation(\"EvaluationTrainee\", fields: [traineeId], references: [id], onDelete: Cascade)\n  instructor User           @relation(\"EvaluationInstructor\", fields: [instructorId], references: [id])\n  course     AcademyCourse? @relation(fields: [courseId], references: [id], onDelete: SetNull)\n\n  @@index([traineeId])\n}\n\n// ---------------------------------------------------------------------------\n// MUTATIONS\n// ---------------------------------------------------------------------------\n\nmodel TransferRequest {\n  id            Int       @id @default(autoincrement())\n  applicantId   Int\n  divisionId    Int\n  subDivisionId Int?\n  motivation    String    @db.Text\n  status        String    @default(\"PENDING\") // PENDING, ACCEPTED, REJECTED, WITHDRAWN\n  decisionNote  String?   @db.Text\n  decidedById   Int?\n  decidedAt     DateTime?\n  createdAt     DateTime  @default(now())\n\n  applicant User  @relation(\"TransferApplicant\", fields: [applicantId], references: [id], onDelete: Cascade)\n  decidedBy User? @relation(\"TransferDecider\", fields: [decidedById], references: [id], onDelete: SetNull)\n\n  @@index([status])\n  @@index([divisionId])\n}\n"
}

